const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
let listId=body.list_id;
if(listId==null){ try{ const s=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/settings/records',qs:{filter:'key="brevo"',perPage:1},headers:pbH,json:true}); const v=(s.items&&s.items[0]&&s.items[0].value)||{}; listId=v.list_id; }catch(e){} }
const base='https://api.brevo.com';
const url = (listId!=null) ? (base+'/v3/contacts/lists/'+Number(listId)+'/contacts?limit=1000') : (base+'/v3/contacts?limit=1000');
return [{json:{url, listId: (listId!=null?Number(listId):null)}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const pages=$input.all();
let emails=[];
for(const p of pages){ const cs=(p.json&&p.json.contacts)||[]; for(const c of cs){ if(c&&c.email) emails.push(String(c.email).trim().toLowerCase()); } }
emails=[...new Set(emails)].filter(Boolean);
let imported=0, skipped=0;
for(const email of emails){
  try{ await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/contacts/records',headers:pbH,body:{email,source_type:'brevo'},json:true}); imported++; }
  catch(e){ skipped++; }
}
return [{json:{imported,skipped,total:emails.length}}];
